fun solve(n: Long, edges: Array<Array<Long>>, label: String): Long {
    val nInt = n.toInt()
    val adj = Array(nInt) { mutableListOf<Long>() }
    for (i in 0 until edges.size) {
        val u = edges[i][0]
        val v = edges[i][1]
        adj[u.toInt()].add(v.toInt())
        adj[v.toInt()].add(u.toInt())
    }
    var maxLen = 1L
    fun dfs(current: Int, visited: Long, path: List<Char>): Long {
        val k = path.size
        var isPalindrome = true
        for (i in 0 until k / 2) {
            if (path[i] != path[k - 1 - i]) {
                isPalindrome = false
                break
            }
        }
        if (isPalindrome) {
            maxLen = max(maxLen, k.toLong())
        }
        for (neighbor in adj[current]) {
            if ((visited and (1L shl neighbor)) == 0L) {
                val newVisited = visited or (1L shl neighbor)
                val newPath = path.toMutableList().apply { add(label[neighbor].toChar()) }
                dfs(neighbor, newVisited, newPath)
            }
        }
        return maxLen
    }
    for (start in 0 until nInt) {
        val visited = 1L shl start
        val path = mutableListOf<Char>().apply { add(label[start].toChar()) }
        dfs(start, visited, path)
    }
    return maxLen
}
