fun solve(n: Long, edges: Array<Array<Long>>, label: String): Long {
    val adj = Array(n.toInt()) { mutableListOf<Long>() }
    for (i in 0 until edges.size) {
        val u = edges[i][0]
        val v = edges[i][1]
        adj[u.toInt()].add(v.toInt())
        adj[v.toInt()].add(u.toInt())
    }

    var maxLen = 1L

    fun dfs(node: Long, visited: Long, path: List<Long>): Unit {
        val currentLabels = path.map { label[it.toInt()] }.joinToString("")
        if (currentLabels.isNotEmpty() && isPalindrome(currentLabels)) {
            maxLen = max(maxLen, path.size.toLong())
        }
        for (neighbor in adj[node.toInt()]) {
            if ((visited and (1 shl neighbor.toInt())) == 0L) {
                dfs(neighbor, visited or (1 shl neighbor.toInt()), path + neighbor)
            }
        }
    }

    for (i in 0 until n.toInt()) {
        dfs(i.toLong(), 1 shl i, listOf(i))
    }

    return maxLen
}

fun isPalindrome(s: String): Boolean {
    return s == s.reversed()
